from fixtures import make_test_result


def _reachable(std_graph, root):
    visited = set()
    stack = [root]
    while stack:
        node = stack.pop()
        if node in visited:
            continue
        visited.add(node)
        stack.extend(std_graph.get(node, {}))
    return visited


def test_recursive_rdmst_cycle_expansion(module):
    graph = {
        0: {1: 5, 2: 4, 3: 9},
        1: {2: 1, 3: 4, 0: 8},
        2: {1: 1, 3: 2, 0: 7},
        3: {1: 3, 2: 6, 0: 10},
    }
    result = module.provided.compute_rdmst(graph, 0)
    total_edges = sum(len(incoming) for incoming in result.values())
    passed = (
        0 in result
        and len(result[0]) == 0
        and total_edges == 3
        and set(result.keys()) == {0, 1, 2, 3}
    )
    return make_test_result(passed, "4 nodes with 3 incoming edges total", result)


def test_infer_transmap_returns_standard_tree(module):
    result = module.infer_transmap("patient_sequences.txt", "patient_traces.txt")
    total_edges = sum(len(outgoing) for outgoing in result.values())
    passed = (
        1 in result
        and total_edges == len(result) - 1
        and _reachable(result, 1) == set(result)
    )
    return make_test_result(passed, "standard rooted tree reachable from patient 1", result)
